    (1756, 'I try to keep in shape by going for a run every now and then.', 'phrase', 'e713db1953ff6af9e9ec6ed8112a98084ed68fba007b1ca3c2c1bb04cd66ce32', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_tempo_libero_hobby_033", "note_culturale": "Tenersi in forma significa mantenersi in buona salute fisica."}', NULL),
