    (1758, 'Maalaaminen auttaa minua tuomaan esiin sen, mitä minulla on sisälläni.', 'phrase', '17d0b8d514a196c272a2a60cdb376375af788f69c83f80d1f0696e6068a94e66', 'B1', true, 'medium', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_tempo_libero_hobby_034", "note_culturale": "Tirare fuori quello che si ha dentro significa esprimere i propri sentimenti e pensieri."}', NULL),
